// ============================================================
// InitCore v1.0 — Validación de Telegram
// Telegram Bot API permite definir un secret_token al registrar
// el webhook (setWebhook). Ese token llega en el header:
//   X-Telegram-Bot-Api-Secret-Token
// Se compara con TELEGRAM_WEBHOOK_SECRET del entorno.
// ============================================================

const headers = $input.first().json.headers || {};
const receivedSecret =
  headers['x-telegram-bot-api-secret-token'] ||
  headers['X-Telegram-Bot-Api-Secret-Token'];

const expectedSecret = $env.TELEGRAM_WEBHOOK_SECRET;

if (!expectedSecret) {
  throw new Error('TELEGRAM_WEBHOOK_SECRET no está definido en variables de entorno');
}

if (!receivedSecret || receivedSecret !== expectedSecret) {
  return [{
    json: {
      valid: false,
      reason: 'Secret token inválido o ausente',
      status: 'rejected'
    }
  }];
}

// Validación adicional: el update debe contener message o edited_message
const body = $input.first().json.body || {};
if (!body.message && !body.edited_message && !body.channel_post) {
  return [{
    json: {
      valid: false,
      reason: 'Update Telegram sin message/edited_message/channel_post',
      status: 'rejected'
    }
  }];
}

return [{ json: { ...body, valid: true } }];

const crypto = require('crypto');
const sha256 = s => crypto.createHash('sha256').update(String(s),'utf-8').digest('hex');
const stripHtml = html => !html ? '' : String(html)
  .replace(/<script[\s\S]*?<\/script>/gi,'')
  .replace(/<style[\s\S]*?<\/style>/gi,'')
  .replace(/<\/?[^>]+>/g,'')
  .replace(/&nbsp;/gi,' ').replace(/&amp;/gi,'&').replace(/&lt;/gi,'<')
  .replace(/&gt;/gi,'>').replace(/&quot;/gi,'"').replace(/&#39;|&apos;/gi,"'")
  .replace(/\s+/g,' ').trim();
const normForHash = t => (t||'').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^\p{L}\p{N}]+/gu,' ').replace(/\s+/g,' ').trim();

// ============================================================
// InitCore v1.0 — Extracción Telegram → formato unificado
// Maneja: text, photo, document, voice, video, caption
// ============================================================

const update = $input.first().json;
const msg = update.message || update.edited_message || update.channel_post || {};
const from = msg.from || {};

// Texto o caption (para media con descripción)
const text = (msg.text || msg.caption || '').toString().substring(0, 5000);

// Construcción del array de media
const media = [];
const botToken = $env.TELEGRAM_BOT_TOKEN;
const fileUrlBase = `https://api.telegram.org/file/bot${botToken}/`;

// NOTA: Telegram devuelve file_id; el archivo real se obtiene con getFile.
// Aquí guardamos el file_id y el tipo; el core (o un job posterior) descargará.
if (Array.isArray(msg.photo) && msg.photo.length > 0) {
  // La última entrada es la de mayor resolución
  const largest = msg.photo[msg.photo.length - 1];
  media.push({ file_id: largest.file_id, type: 'image/jpeg', width: largest.width, height: largest.height });
}
if (msg.document) {
  media.push({ file_id: msg.document.file_id, type: msg.document.mime_type || 'application/octet-stream', file_name: msg.document.file_name });
}
if (msg.voice) {
  media.push({ file_id: msg.voice.file_id, type: msg.voice.mime_type || 'audio/ogg', duration: msg.voice.duration });
}
if (msg.video) {
  media.push({ file_id: msg.video.file_id, type: msg.video.mime_type || 'video/mp4', duration: msg.video.duration });
}
if (msg.audio) {
  media.push({ file_id: msg.audio.file_id, type: msg.audio.mime_type || 'audio/mpeg', duration: msg.audio.duration });
}

// Detección de idioma a partir de language_code de Telegram
const language = (from.language_code || 'es').split('-')[0].toLowerCase();

// Nombre completo del usuario
const name = [from.first_name, from.last_name].filter(Boolean).join(' ').trim();

const payload = {
  channel: 'telegram',
  message: {
    text,
    media
  },
  timestamp: new Date(((msg.date || Math.floor(Date.now() / 1000)) * 1000)).toISOString(),
  context: {
    name,
    email: '',
    phone: '',
    language
  },
  metadata: {
    source: 'telegram_adapter',
    adapter_version: '1.0.0',
    telegram_update_id: update.update_id,
    telegram_message_id: msg.message_id,
    telegram_chat_id: msg.chat?.id,
    telegram_chat_type: msg.chat?.type,
    telegram_username: from.username || '',
    file_url_base: fileUrlBase
  },
  status: 'pending',
  // El core generará user_id = sha256('telegram' + from.id)
  _user_identifier: String(from.id || '')
};


const message_id = crypto.randomUUID();
const sender_id = sha256(payload.channel + ':' + payload._user_identifier);
const cleanText = stripHtml(payload.message?.text || '');
const mediaFingerprint = (payload.message?.media||[]).map(m => m.url || m.file_id || '').join('|');
const hashKey = normForHash(cleanText);
const hash = sha256(payload.channel + ':' + sender_id + ':' + (hashKey || mediaFingerprint || message_id));

// Flatten out the response so it is easy to persist to messages table, AND hold the 5 fields
const newPayload = {
  channel: payload.channel,
  message_id: message_id,
  sender_id: sender_id,
  user_id: sender_id, // keep it around for the messages table insert
  text: cleanText,
  hash: hash,
  media: payload.message?.media || [],
  ts: payload.timestamp || new Date().toISOString(),
  context: payload.context || {},
  metadata: payload.metadata || {}
};

return [{ json: newPayload }];

// Handler de error — formato idéntico al WhatsApp adapter
const err = $input.first().json;
return [{
  json: {
    channel: 'telegram',
    error_message: err.error?.message || 'Error desconocido en Telegram adapter',
    error_stack: err.error?.stack || '',
    payload: err,
    timestamp: new Date().toISOString(),
    retry_count: err.$execution?.retryCount || 0
  }
}];
